		{
			compressor = new MapFileCompressor(this);
			compressor.BuildCompressedString();
			ExposeComponents();
			compressor.ExposeData();
			HashSet<string> hashSet = new HashSet<string>();
			if (Scribe.EnterNode("things"))
			{
				try
