		}
		return default(T);
	}

	public static bool TryGetVar<T>(string name, out T var)
	{
		if (data.TryGetValue(name, out var value))
		{
			var = (T)value;
			return true;
		}
		var = default(T);
		return false;
	}

	public static T GetOrGenerateVar<T>(string name)
	{
		T var = GetVar<T>(name);
		if (var != null)
		{
			return var;
		}
		var = (T)Activator.CreateInstance(typeof(T));
		SetVar(name, var);
		return var;
	}

