	private static int GetSeedPart(List<GenStepWithParams> genSteps, int index)
	{
		int seedPart = genSteps[index].def.genStep.SeedPart;
		int num = 0;
		for (int i = 0; i < index; i++)
		{
			if (tmpGenSteps[i].def.genStep.SeedPart == seedPart)
			{
				num++;
			}
		}
		return seedPart + num;
	}
