	public T GetComponent<T>() where T : MapComponent
	{
		for (int i = 0; i < components.Count; i++)
		{
			if (components[i] is T result)
			{
				return result;
			}
		}
		return null;
	}

	public MapComponent GetComponent(Type type)
	{
		for (int i = 0; i < components.Count; i++)
		{
			if (type.IsInstanceOfType(components[i]))
			{
				return components[i];
			}
		}
		return null;
	}

